    public static PowerDef Get(int id) =>
        Array.Find(_all, p => p.Id == id) is { Id: > 0 } def
            ? def
            : throw new ArgumentException($"Unknown power id {id}");

    public static int? FindId(string name) =>
        Array.Find(_all, p => p.Name == name) is { Id: > 0 } def
            ? def.Id
            : null;
